BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?sigName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "PEAS-CommonService" .

  {
    ?pkg vocab:Package_packagedElement+ ?signal .
  }
  UNION
  {
    ?pkg vocab:Element_ownedElement+ ?signal .
  }

  ?signal rdf:type vocab:signal .
  OPTIONAL { ?signal vocab:NamedElement_name ?sigName . }
}
ORDER BY ?sigName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childType ?childName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "PEAS-CommonService" .

  {
    ?pkg vocab:Package_packagedElement+ ?child .
  }
  UNION
  {
    ?pkg vocab:Element_ownedElement+ ?child .
  }

  ?child rdf:type ?childType .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }

  FILTER(
    CONTAINS(LCASE(STR(?childName)), "sig") ||
    CONTAINS(LCASE(STR(?childName)), "signal") ||
    CONTAINS(STR(?childType), "Signal")
  )
}
ORDER BY ?childName
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?childType (COUNT(*) AS ?count) WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "PEAS-CommonService" .

  {
    ?pkg vocab:Package_packagedElement+ ?child .
  }
  UNION
  {
    ?pkg vocab:Element_ownedElement+ ?child .
  }

  ?child rdf:type ?childType .
}
GROUP BY ?childType
ORDER BY DESC(?count)
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?sigEvent ?name WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "PEAS-CommonService" .

  ?pkg (^vocab:Package_packagedElement|^vocab:Element_ownedElement)* ?sigEvent .
  ?sigEvent rdf:type vocab:SignalEvent .
  OPTIONAL { ?sigEvent vocab:NamedElement_name ?name . }
}
ORDER BY ?name
LIMIT 25
